var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으응...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"늦잠이야. 한참 기다렸어.","JPN":"お寝坊さん。ずいぶん待ったのよ。","ENG":"You sure sleep in. I've been waiting a while.","TWN":"睡過頭了，我等你好久了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...음?","JPN":"……ん？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"히익-!","JPN":"ひいっ！","ENG":"Eek...!","TWN":"咿—！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"놀래킨 적 없는데.","JPN":"驚かしてないのに。","ENG":"I didn't do anything to startle you.","TWN":"我又沒嚇你。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그야 네놈이 흉악하게 생겨 먹지 않았느냐.","JPN":"それはお前が凶悪な顔をしているからであろう。","ENG":"Well, that's because you look vicious.","TWN":"那是因為你長得太兇了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"실례네. 너도 뿔 달고 있는 주제에.","JPN":"失礼ね。あなただって角が生えてるくせに。","ENG":"Rude. Says the one with horns.","TWN":"真失禮，你自己還長著角呢。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...으익! 이 몸에게 무슨 짓을 한 것이냐! 여긴 또 어디고!","JPN":"……ぐぎぎっ！　吾輩に何をした！　ここはどこだ！","ENG":"...Ghk! What did you do to me?! And where is this place?!","TWN":"……唔！你對我做了什麼！這裡又是什麼地方！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"여긴, <color=#ffd34c>감옥</color>이야.","JPN":"ここは、<color=#ffd34c>牢獄</color>だよ。","ENG":"This is a <color=#ffd34c>prison</color>.","TWN":"這裡是<color=#ffd34c>監獄</color>。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"일단은 널 빼앗은 입장이니까. 아무 데나 풀어둘 수는 없거든.","JPN":"一応はあなたを奪った立場だから。自由にさせておくわけにもいかないのよ。","ENG":"For now, I did steal you away. I can't exactly let you run loose anywhere you want.","TWN":"畢竟我算是把你奪走的人，總不能隨便放你出去。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"감옥은 싫다! 날 내보내거라!","JPN":"牢獄はイヤだぞ！　吾輩を解放しろ！","ENG":"I hate prisons! Let me out!","TWN":"我討厭監獄！快放我出去！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"싫다면?","JPN":"嫌だと言ったら？","ENG":"And if I refuse?","TWN":"如果我說不要呢？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으기이이익...!","JPN":"ぐぬぬぬぬっ……！","ENG":"Grrr...!","TWN":"唔唔唔……！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"사실 넌 이곳에 갇혀있는 게 아니야. 원한다면 얼마든지 이곳을 나갈 수 있어.","JPN":"実は、あなたをここに閉じ込めているわけじゃないの。望めばいくらでもここから出られるよ。","ENG":"Actually, you aren't trapped here.","TWN":"其實你並沒有被關起來。只要你願意，隨時都可以離開這裡。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"네가 나의 일부라는 사실을 받아들이기만 한다면 말이야.","JPN":"あなたが私の一部だっていう事実を受け入れればね。","ENG":"You can leave this place whenever you want. As long as you accept that you are a part of me.","TWN":"只要你接受你是我的一部分這件事。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그게... 무슨 소리인 것이냐?","JPN":"それは……どういうことだ？","ENG":"What... are you talking about?","TWN":"那……那是什麼意思？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸이 네 녀석과 같을 리 없지 않더냐!","JPN":"この吾輩がお前と一緒なわけないであろう！","ENG":"There's no way I could be the same as you!","TWN":"我怎麼可能和你一樣！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"넌 마왕이잖아. 그렇지?","JPN":"あなたは魔王でしょう？　違うの？","ENG":"You're a Demon Lord, aren't you?","TWN":"你是魔王吧？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 마왕이다.","JPN":"吾輩は魔王である。","ENG":"I am a Demon Lord.","TWN":"沒錯，我就是魔王。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"하지만, 이 몸은 네놈처럼...","JPN":"だが、吾輩はお前のように……","ENG":"But I don't...","TWN":"但是我不像你……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...너처럼 사람을 해치면서 웃지 않아!!","JPN":"……お前のように人を傷つけながら笑わん！！","ENG":"...laugh while hurting people like you do!!","TWN":"……不像你那樣，一邊傷害人一邊笑！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 소녀의 몸. 아발론의 작은 왕은 어린 나이에 요절할 운명을 타고났어.","JPN":"その少女の体。アバロンの小さな王は早世する運命だった。","ENG":"That flesh. Avalon's little queen was born fated to die young.","TWN":"那個少女的身體是阿瓦隆的小王，她本來注定會在年幼時早逝。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 악마는 그녀의 영혼을 구하기 위해, 내 일부를 융합해 그 운명을 비틀었지.","JPN":"でも悪魔は彼女の魂を救うために、私の一部を融合してその運命を捻じ曲げたの。","ENG":"But to save her soul, a demon fused part of me into her and twisted that fate.","TWN":"但惡魔為了拯救她的靈魂，融合了我的一部分，扭曲了那個命運。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"악마는 가짜다. 그런 건 본 적도 없느니라.","JPN":"悪魔など偽物だ。そのようなもの、見たこともない。","ENG":"The demon is a fake. I've never seen such a thing.","TWN":"惡魔是假的，我從沒見過。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아니. 넌 누구보다 그 악마를 잘 알아.","JPN":"いいえ。あなたは誰よりもその悪魔のことをよく知ってるよ。","ENG":"No. You know that demon better than anyone.","TWN":"不，你比任何人都清楚那個惡魔。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마는 네가 있던 세계에서... 그레모리라는 이름으로 불렸거든.","JPN":"その悪魔はあなたのいた世界で……グレモリーという名前で呼ばれていたから。","ENG":"In the world you were in... that demon goes by the name Gremory.","TWN":"在你所在的世界，那個惡魔被稱為……葛茉莉。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"넌 본래 죽었어야 할 소녀의 몸에 갇혀 있던, 마왕의 파편이야.","JPN":"あなたは本来死ぬべきだった少女の体に閉じ込められていた、魔王の破片。","ENG":"You are a Fragment of a Demon Lord, trapped inside the body of a girl who was supposed to die.","TWN":"你只是被困在一個本該死去的少女體內的魔王碎片。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마가 우릴 이용한 거라고.","JPN":"悪魔が私たちを利用したのよ。","ENG":"That demon used us.","TWN":"那個惡魔一直在利用我們。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그럴 리가 없다.","JPN":"そ、そんなわけない。","ENG":"Th-that can't be.","TWN":"不、不可能。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그레모리는 날 이용한 게 아니라, 이 몸의 충실한 하수인...","JPN":"グレモリーは吾輩を利用したのではなく、吾輩の忠実な下僕……","ENG":"Gremory didn't use me. She is my loyal servant...","TWN":"葛茉莉不是利用我，她是我忠誠的部下……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"넌 마왕이 아니라 임금님이야.","JPN":"あなたは魔王じゃなくて、王様よ。","ENG":"You're not a Demon Lord. You're a queen.","TWN":"你不是魔王，你只是國王而已。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐, 자길 뭐라고 부르든 네 마음이겠지만.","JPN":"まあ、自分のことをどう呼ぼうがあなたの自由でしょうけど。","ENG":"Well, call yourself whatever you want.","TWN":"不過隨你高興怎麼稱呼自己。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};